import{_ as t,o as e,c as o,a0 as r}from"./chunks/framework.CDWbKMqd.js";const i="/MewBlog/images/waiba-1.jpg",s="/MewBlog/images/waiba-2.jpg",b=JSON.parse('{"title":"我家的猫：外八","description":"","frontmatter":{"title":"我家的猫：外八","date":"2026-07-03T00:00:00.000Z","category":"life","tags":["猫","日常"],"summary":"一只前脚外八、温顺胆小、喜欢看电脑屏幕的小猫。从流浪基地到我的房间，外八已经来了四个多月了。"},"headers":[],"relativePath":"posts/my-cat-waiba.md","filePath":"posts/my-cat-waiba.md"}'),p={name:"posts/my-cat-waiba.md"};function l(n,a,c,h,d,m){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="我家的猫-外八" tabindex="-1">我家的猫：外八 <a class="header-anchor" href="#我家的猫-外八" aria-label="Permalink to &quot;我家的猫：外八&quot;">​</a></h1><p>外八是今年 2 月 28 号来到我身边的。</p><p><img src="'+i+'" alt="外八"></p><h2 id="名字的由来" tabindex="-1">名字的由来 <a class="header-anchor" href="#名字的由来" aria-label="Permalink to &quot;名字的由来&quot;">​</a></h2><p>外八的前脚掌往外拐，走起路来特别明显，像人走路外八字——所以就叫外八了。不是什么深奥的名字，一眼看过去就是这个感觉。</p><h2 id="从哪里来" tabindex="-1">从哪里来 <a class="header-anchor" href="#从哪里来" aria-label="Permalink to &quot;从哪里来&quot;">​</a></h2><p>从流浪基地领养的。不知道具体品种，看起来有加菲和矮脚的基因——脸扁扁的，腿短短的。不是那种贵价猫舍出来的，但刚刚好。</p><h2 id="性格" tabindex="-1">性格 <a class="header-anchor" href="#性格" aria-label="Permalink to &quot;性格&quot;">​</a></h2><p>外八非常温顺，来了四个多月，<strong>从来没哈过气</strong>。</p><p>胆子不大，有点动静就会警觉。但好奇心又特别重——我的电脑屏幕一开，它就会凑过来看，不知道是看光标移动还是看代码滚动。放猫电视的时候更夸张，直接上爪子抓屏幕里的鸟。</p><p>不太喜欢高处，这点跟大多数猫不太一样。不知道是不是跟它短腿基因有关，也可能是单纯不喜欢。</p><p><img src="'+s+'" alt="外八"></p><h2 id="这四个月" tabindex="-1">这四个月 <a class="header-anchor" href="#这四个月" aria-label="Permalink to &quot;这四个月&quot;">​</a></h2><p>刚来的时候它身体不太好，前阵子带去看医生，现在已经完全康复了。</p><p>从离职到面试到搬家到培训，这段时间发生了很多事。外八一直是房间里不变的那个——饿了吃饭，困了睡觉，我焦虑的时候它就趴在不远的地方。什么都不用做，存在本身就够了。</p><hr><blockquote><p>有时候想想，不是我领养了它，是它接纳了我。</p></blockquote>',17)])])}const u=t(p,[["render",l]]);export{b as __pageData,u as default};
